#include <bits/stdc++.h>
using namespace std;
int n,r[100005],s[100005],cnt;
int main(){
	//freopen("duel.in","r",stdin);
	//freopen("duel.out","w",stdout);
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&r[i]);
	sort(r+1,r+n+1);
	for(int i=1;i<=n;i++){
		if(i==1 || r[i]>r[i-1])
			cnt++;
		s[cnt]++;
	}
	int ans=n,sum=s[1];
	for(int i=2;i<=cnt;i++){
		if(sum<s[i])
			ans-=sum,sum=0;
		else
			ans-=s[i],sum-=s[i];
		sum+=s[i];
	}
	printf("%d",ans);
	return 0;
}
